import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const scriptDir = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(scriptDir, "..");

const sources = [
  {
    input: resolve(repoRoot, "docs/userguide.md"),
    exportName: "USER_GUIDE_EN_MARKDOWN",
  },
  {
    input: resolve(repoRoot, "docs/userguide.fr.md"),
    exportName: "USER_GUIDE_FR_MARKDOWN",
  },
];

const outPath = resolve(repoRoot, "src/content/generatedUserGuides.ts");

const lines = [
  "// Generated by scripts/sync-userguides.mjs",
  "// Do not edit this file manually.",
  "",
];

for (const source of sources) {
  const markdown = readFileSync(source.input, "utf8");
  lines.push(`export const ${source.exportName} = ${JSON.stringify(markdown)};`);
  lines.push("");
}

mkdirSync(dirname(outPath), { recursive: true });
writeFileSync(outPath, `${lines.join("\n")}\n`, "utf8");
console.log(`Synced user guides to ${outPath}`);
